#!/bin/bash

# Define the AIDE configuration file path
AIDE_CONF="/etc/aide.conf"

# Check if the AIDE configuration file exists
if [[ ! -f "$AIDE_CONF" ]]; then
    echo "AIDE configuration file not found at $AIDE_CONF"
    exit 1
fi

# Backup the original AIDE configuration file
cp "$AIDE_CONF" "${AIDE_CONF}.bak"

# Function to ensure extended attributes are included in a ruleset
ensure_xattr_in_ruleset() {
    local ruleset="$1"
    if ! grep -q "xattrs" <<< "$ruleset"; then
        echo "${ruleset}xattrs"
    else
        echo "$ruleset"
    fi
}

# Process the AIDE configuration file
awk '
    BEGIN { in_ruleset = 0 }
    /^BEGIN/ { in_ruleset = 1 }
    /^END/ { in_ruleset = 0 }
    {
        if (in_ruleset && $0 ~ /^[A-Za-z0-9_]+[ \t]*=[ \t]*[^#]/) {
            split($0, parts, "=")
            ruleset_name = parts[1]
            ruleset_value = parts[2]
            gsub(/^[ \t]+|[ \t]+$/, "", ruleset_value)
            if (ruleset_value !~ /xattrs/) {
                print ruleset_name " = " ruleset_value "xattrs"
            } else {
                print $0
            }
        } else {
            print $0
        }
    }
' "$AIDE_CONF" > "${AIDE_CONF}.tmp"

# Replace the original configuration with the modified one
mv "${AIDE_CONF}.tmp" "$AIDE_CONF"

echo "AIDE configuration updated to include extended attributes in all rulesets."
